/**
 * MedX focus accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Focus ring styles and visible focus management.
 */
const FOCUS_TOKENS = Object.freeze({
  primary: { value: "a11y-focus-primary", scope: "a11y" },
  secondary: { value: "a11y-focus-secondary", scope: "a11y" },
  muted: { value: "a11y-focus-muted", scope: "a11y" },
  accent: { value: "a11y-focus-accent", scope: "a11y" },
  surface: { value: "a11y-focus-surface", scope: "a11y" },
});

const FOCUS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const FOCUS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const focusRegistry = new Map();
const FOCUS_listeners = new Set();
let FOCUS_seq = 0;

function createFocusId(prefix = "medx-a11y-focus") {
  FOCUS_seq += 1;
  return `${prefix}-${FOCUS_seq}`;
}

function registerFocus(config = {}) {
  const entryId = config.id ?? createFocusId();
  const preset = FOCUS_PRESETS[config.preset ?? "default"] ?? FOCUS_PRESETS.default;
  const token = FOCUS_TOKENS[config.token ?? preset.token] ?? FOCUS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: FOCUS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  focusRegistry.set(entryId, entry);
  notifyFocusListeners("register", entry);
  return entry;
}

function updateFocus(id, patch = {}) {
  const entry = focusRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyFocusListeners("update", entry);
  return entry;
}

function resolveFocus(id) {
  const entry = focusRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listFocusEntries(filter = {}) {
  let items = Array.from(focusRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onFocusEvent(listener) {
  FOCUS_listeners.add(listener);
  return () => FOCUS_listeners.delete(listener);
}

function notifyFocusListeners(type, entry) {
  for (const listener of FOCUS_listeners) {
    try {
      listener({ type, entry, registrySize: focusRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:focus] listener error", err.message);
    }
  }
}

function getFocusMetrics() {
  const items = listFocusEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(FOCUS_TOKENS).length,
    presets: Object.keys(FOCUS_PRESETS).length,
  };
}

async function runMedxFocus() {
  console.log("[medx:ui:a11y:focus] runtime initialized");
  console.log(`[medx:ui:a11y:focus] tokens=${Object.keys(FOCUS_TOKENS).length} presets=${Object.keys(FOCUS_PRESETS).length}`);

  const events = [];
  onFocusEvent((e) => events.push(e.type));

  const domains = Object.keys(FOCUS_SUPPLY_CHAIN);
  const presets = Object.keys(FOCUS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerFocus({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/focus" },
    });
  }

  const first = listFocusEntries()[0];
  if (first) updateFocus(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getFocusMetrics();
  const resolved = first ? resolveFocus(first.id) : null;

  console.log(`[medx:ui:a11y:focus] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:focus] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:focus] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:focus] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:focus] bootstrap complete");
}

module.exports = runMedxFocus;
